'use client'
import { cn, useSignal, useSignalEffect, useSignals } from '@cascivo/core'
import { builtin, t } from '@cascivo/i18n'
import { useRef, type ReactNode, type KeyboardEvent } from 'react'
import styles from './modal.module.css'

export interface ModalProps {
  open?: boolean
  onClose?: () => void
  title?: string
  description?: string
  children?: ReactNode
  className?: string
  size?: 'sm' | 'md' | 'lg'
}

export function Modal({
  open = false,
  onClose,
  title,
  description,
  children,
  className,
  size = 'md',
}: ModalProps) {
  useSignals()
  const dialogRef = useRef<HTMLDialogElement>(null)
  const onCloseRef = useRef(onClose)
  onCloseRef.current = onClose

  const isOpen = useSignal(open)
  // Sync controlled prop into signal — no-op when value unchanged
  isOpen.value = open

  useSignalEffect(() => {
    const dialog = dialogRef.current
    if (!dialog) return
    if (isOpen.value) {
      if (!dialog.open) dialog.showModal()
    } else {
      if (dialog.open) dialog.close()
    }
  })

  useSignalEffect(() => {
    const dialog = dialogRef.current
    if (!dialog) return
    const handler = () => onCloseRef.current?.()
    dialog.addEventListener('close', handler)
    return () => dialog.removeEventListener('close', handler)
  })

  const handleBackdropClick = (e: React.MouseEvent<HTMLDialogElement>) => {
    if (e.target === dialogRef.current) {
      dialogRef.current?.close()
    }
  }

  const handleKeyDown = (e: KeyboardEvent<HTMLDialogElement>) => {
    if (e.key === 'Escape') {
      e.preventDefault()
      dialogRef.current?.close()
    }
  }

  return (
    <dialog
      ref={dialogRef}
      data-size={size}
      className={cn(styles['dialog'], className)}
      onClick={handleBackdropClick}
      onKeyDown={handleKeyDown}
      aria-labelledby={title ? 'cascade-modal-title' : undefined}
      aria-describedby={description ? 'cascade-modal-desc' : undefined}
    >
      <div className={styles['panel']}>
        {(title || onClose) && (
          <div className={styles['header']}>
            {title && (
              <h2 id="cascade-modal-title" className={styles['title']}>
                {title}
              </h2>
            )}
            {onClose && (
              <button
                type="button"
                className={styles['close']}
                onClick={() => dialogRef.current?.close()}
                aria-label={t(builtin.modal.close)}
              >
                ✕
              </button>
            )}
          </div>
        )}
        {description && (
          <p id="cascade-modal-desc" className={styles['description']}>
            {description}
          </p>
        )}
        <div className={styles['body']}>{children}</div>
      </div>
    </dialog>
  )
}

@layer cascivo.component {
  .dialog {
    padding: 0;
    border: none;
    border-radius: var(--cascivo-radius-overlay);
    background: transparent;
    max-height: calc(100dvh - var(--cascivo-space-16));
    overflow: visible;

    /* Exit animation: transitioning `display`/`overlay` with allow-discrete
       keeps the dialog visible (and in the top layer) until the fade ends */
    opacity: 0;
    scale: 0.96;
    transition:
      opacity var(--cascivo-motion-exit),
      scale var(--cascivo-motion-exit),
      display var(--cascivo-duration-150) allow-discrete,
      overlay var(--cascivo-duration-150) allow-discrete;

    &[open] {
      opacity: 1;
      scale: 1;
      transition:
        opacity var(--cascivo-motion-enter),
        scale var(--cascivo-motion-enter),
        display var(--cascivo-duration-200) allow-discrete,
        overlay var(--cascivo-duration-200) allow-discrete;

      @starting-style {
        opacity: 0;
        scale: 0.96;
      }
    }

    /* Backdrop */
    &::backdrop {
      background-color: rgb(0 0 0 / 0.5);
      backdrop-filter: blur(2px);
      opacity: 0;
      transition:
        opacity var(--cascivo-motion-exit),
        display var(--cascivo-duration-150) allow-discrete,
        overlay var(--cascivo-duration-150) allow-discrete;
    }

    &[open]::backdrop {
      opacity: 1;
      transition:
        opacity var(--cascivo-motion-enter),
        display var(--cascivo-duration-200) allow-discrete,
        overlay var(--cascivo-duration-200) allow-discrete;

      @starting-style {
        opacity: 0;
      }
    }

    &[data-size='sm'] {
      --_modal-width: 24rem;
    }
    &[data-size='md'] {
      --_modal-width: 32rem;
    }
    &[data-size='lg'] {
      --_modal-width: 48rem;
    }
  }

  .panel {
    width: var(--_modal-width, 32rem);
    max-width: calc(100vw - var(--cascivo-space-8));
    background-color: var(--cascivo-color-surface-overlay);
    border-radius: var(--cascivo-radius-overlay);
    border: 1px solid var(--cascivo-color-border);
    box-shadow: var(--cascivo-shadow-overlay);
    overflow: hidden;
  }

  .header {
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding: var(--cascivo-space-6);
    padding-block-end: var(--cascivo-space-4);
    border-block-end: 1px solid var(--cascivo-color-border);
  }

  .title {
    font-family: var(--cascivo-font-sans);
    font-size: var(--cascivo-text-lg);
    font-weight: var(--cascivo-font-semibold);
    color: var(--cascivo-color-text);
    margin: 0;
    line-height: var(--cascivo-leading-tight);
  }

  .close {
    display: flex;
    align-items: center;
    justify-content: center;
    width: 2rem;
    height: 2rem;
    padding: 0;
    font-size: var(--cascivo-text-sm);
    color: var(--cascivo-color-text-muted);
    background: transparent;
    border: none;
    border-radius: var(--cascivo-radius-control);
    cursor: pointer;
    transition:
      color var(--cascivo-duration-150) var(--cascivo-ease-out),
      background-color var(--cascivo-duration-150) var(--cascivo-ease-out);

    &:hover {
      color: var(--cascivo-color-text);
      background-color: var(--cascivo-color-bg-subtle);
    }

    &:focus-visible {
      outline: none;
      box-shadow: var(--cascivo-focus-ring);
    }
  }

  .description {
    padding-inline: var(--cascivo-space-6);
    padding-block-start: var(--cascivo-space-4);
    font-family: var(--cascivo-font-sans);
    font-size: var(--cascivo-text-sm);
    color: var(--cascivo-color-text-subtle);
    margin: 0;
    line-height: var(--cascivo-leading-relaxed);
  }

  .body {
    padding: var(--cascivo-space-6);
  }

  @media (max-width: 40rem) {
    .dialog {
      /* Pin to bottom viewport edge — bottom-sheet */
      margin: 0;
      max-block-size: 90dvh;
    }

    .panel {
      inline-size: 100%;
      max-inline-size: 100%;
      border-end-start-radius: 0;
      border-end-end-radius: 0;
      border-start-start-radius: var(--cascivo-radius-overlay);
      border-start-end-radius: var(--cascivo-radius-overlay);
      max-block-size: 90dvh;
      overflow-y: auto;
      /* Safe area for home indicator on iOS */
      padding-block-end: env(safe-area-inset-bottom, 0);
    }
  }

  @media (prefers-reduced-motion: reduce) {
    .dialog {
      transition: none;
    }
    .dialog[open] {
      transition: none;
    }
  }
}

@media (forced-colors: active) {
  .panel {
    border: 1px solid ButtonText;
  }

  .close:focus-visible {
    outline: 2px solid Highlight;
    outline-offset: 2px;
  }
}
